import org.springframework.http.HttpStatus;
import org.springframework.http.ResponseEntity;
import org.springframework.web.bind.annotation.*;
import org.springframework.web.multipart.MultipartFile;

import javax.servlet.http.HttpServletRequest;
import java.io.File;
import java.io.IOException;
import java.nio.file.*;
import java.util.Arrays;
import java.util.List;

@RestController
public class FileUploadController {
    private static final List<String> VALID_CONTENT_TYPES = Arrays.asList("image/png", "image/jpeg", "image/gif");
    private static final String UPLOAD_PATH = "/public/uploads/";

    @PostMapping("/upload")
    public ResponseEntity<?> uploadUserProfilePicture(@RequestParam("file") MultipartFile file, HttpServletRequest request) {
        if (!VALID_CONTENT_TYPES.contains(file.getContentType())) {
            return new ResponseEntity<>("Invalid file format.", HttpStatus.BAD_REQUEST);
        }

        try {
            String fileOriginalName = file.getOriginalFilename();
            Path filePath = Paths.get(UPLOAD_PATH + fileOriginalName);
            Files.copy(file.getInputStream(), filePath, StandardCopyOption.REPLACE_EXISTING);
        } catch (IOException e) {
            return new ResponseEntity<>("File upload error.", HttpStatus.INTERNAL_SERVER_ERROR);
        }

        String fileUrl = request.getScheme() + "://" + request.getServerName() + ":" + request.getServerPort() + UPLOAD_PATH + file.getOriginalFilename();

        return ResponseEntity.ok(fileUrl);
    }
}